// Spawn a geometry collection at runtime
UPROPERTY(EditAnywhere)
UGeometryCollection* WallGeometry;

void AMySpawner::SpawnDestructibleWall(FVector Location) {
    AGeometryCollectionActor* Wall = GetWorld()->SpawnActor<AGeometryCollectionActor>(Location, FRotator::ZeroRotator);
    if (Wall) {
        Wall->GetGeometryCollectionComponent()->SetRestCollection(WallGeometry);
    }
}

// Apply damage to trigger fracture (using Field System)
// In level: place a Field System Actor with a Radial Falloff + External Strain field
// Or from C++:
void AMyWeapon::DamageDestructible(FVector HitLocation) {
    // Use a radial force to trigger Chaos destruction
    URadialForceComponent* RadialForce = NewObject<URadialForceComponent>(this);
    RadialForce->SetWorldLocation(HitLocation);
    RadialForce->Radius = 200.f;
    RadialForce->ImpulseStrength = 10000.f;
    RadialForce->bImpulseVelChange = true;
    RadialForce->RegisterComponent();
    RadialForce->FireImpulse();
    RadialForce->DestroyComponent();
}
